{
  "terms": [
    {
      "term": "Atom",
      "simpleDefinition": "The basic building block of all matter, consisting of a central nucleus and orbiting electrons.",
      "anchor": "Think of it like a tiny solar system with a sun in the middle and planets orbiting around.",
      "misconception": "Thinking atoms are solid balls; they are actually mostly empty space with particles inside."
    },
    {
      "term": "Nucleus",
      "simpleDefinition": "The heavy central part of an atom containing protons and neutrons.",
      "anchor": "The 'engine room' at the very center of the atom.",
      "misconception": "Believing the nucleus moves during electrical flow; it stays fixed while electrons move."
    },
    {
      "term": "Proton",
      "simpleDefinition": "A particle inside the nucleus that carries a positive (+) electrical charge.",
      "anchor": "P for Proton, P for Positive.",
      "misconception": "Thinking protons flow through a copper wire; only electrons move in solid conductors."
    },
    {
      "term": "Neutron",
      "simpleDefinition": "A particle inside the nucleus that has no electrical charge (it is neutral).",
      "anchor": "N for Neutron, N for Neutral.",
      "misconception": "Confusing 'neutral' with 'negative' because they both start with N."
    },
    {
      "term": "Electron",
      "simpleDefinition": "A tiny particle orbiting the nucleus that carries a negative (-) electrical charge.",
      "anchor": "The 'planets' orbiting the nucleus that do all the work in electricity.",
      "misconception": "Thinking electrons are the same size as protons; they are actually much, much smaller."
    },
    {
      "term": "Free Electron",
      "simpleDefinition": "An electron in the outermost shell of an atom that can easily break away and move to another atom.",
      "anchor": "The 'loose change' in an atom's pocket that is easy to spend.",
      "misconception": "Assuming all electrons in an atom are free to move; only the ones furthest from the nucleus usually move."
    },
    {
      "term": "Conductor",
      "simpleDefinition": "A material, like copper or aluminum, that has many free electrons and allows electricity to flow easily.",
      "anchor": "A wide-open motorway for electrons.",
      "misconception": "Thinking a conductor 'creates' electricity; it simply provides the path for electrons to move."
    },
    {
      "term": "Insulator",
      "simpleDefinition": "A material, like PVC or rubber, where electrons are tightly bound and cannot move easily.",
      "anchor": "A brick wall that stops electrons from passing through.",
      "misconception": "Believing insulators have no electrons at all; they have plenty, but they aren't 'free' to move."
    },
    {
      "term": "Electric Current",
      "simpleDefinition": "The directed flow of free electrons through a conductor.",
      "anchor": "A marching army of electrons all moving in the same direction.",
      "misconception": "Confusing the speed of the electrical signal with the physical speed of the individual electrons."
    }
  ],
  "anchorPhrases": [
    "Opposite charges attract; like charges repel.",
    "Electricity is the movement of free electrons.",
    "Conductors have many free electrons; insulators have very few.",
    "The nucleus stays put; the electrons do the traveling."
  ],
  "misconceptionTargets": [
    "Protons do not move through wires; only electrons move.",
    "Insulators still contain atoms and electrons, they just aren't 'free' ones.",
    "Neutrons are neutral (zero charge), not negative.",
    "A material is a conductor because of its atomic structure, not just because it is a metal."
  ]
}

{
  "teachChecks": [
    {
      "title": "Atomic Structure",
      "basicQuestions": [
        {
          "questionText": "What is the name of the heavy, fixed core at the center of an atom?",
          "answerGuidance": [
            "Nucleus"
          ],
          "hint": "It is the central part that contains protons and neutrons.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "Which particle orbits around the central nucleus of an atom?",
          "answerGuidance": [
            "Electron",
            "Electrons"
          ],
          "hint": "These are the tiny particles that move in layers or shells.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "What are the layers called in which electrons orbit the nucleus?",
          "answerGuidance": [
            "Shells"
          ],
          "hint": "Think of the layers of an onion or the orbits of planets.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "In a solid copper wire, why is it only the electrons that move to create electricity rather than the nucleus?",
      "deeperAnswerGuidance": [
        "The nucleus is a fixed core",
        "The nucleus is stationary",
        "Electrons are the orbiting particles",
        "Electrons are the parts that can move"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP5"
      ],
      "hint": "Consider which part of the atom is described as 'fixed' and which part is 'orbiting'."
    },
    {
      "title": "Electrical Charge",
      "basicQuestions": [
        {
          "questionText": "What type of electrical charge does a proton carry?",
          "answerGuidance": [
            "Positive",
            "Positive charge",
            "+"
          ],
          "hint": "Remember: P for Proton and P for...",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the electrical charge of a neutron?",
          "answerGuidance": [
            "Neutral",
            "No charge",
            "Zero charge"
          ],
          "hint": "Remember: N for Neutron and N for...",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "What do two electrical charges of the same type (like charges) do when placed near each other?",
          "answerGuidance": [
            "Repel",
            "Push away"
          ],
          "hint": "Opposites attract, but identical charges do the opposite.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "If an atom contains an equal number of protons and electrons, why does it have no overall electrical charge?",
      "deeperAnswerGuidance": [
        "Positive and negative charges cancel out",
        "The charges balance each other",
        "The total charge becomes neutral",
        "Equal amounts of opposite charges result in zero charge"
      ],
      "deeperSourceTeachingPointIds": [
        "TP2",
        "TP3",
        "TP4"
      ],
      "hint": "Think about what happens when you add a positive number to an equal negative number."
    },
    {
      "title": "Free Electrons",
      "basicQuestions": [
        {
          "questionText": "What is the specific name for the outermost shell of an atom?",
          "answerGuidance": [
            "Valence shell"
          ],
          "hint": "This is the layer furthest from the nucleus.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What is the term for an electron that has broken away from its parent atom?",
          "answerGuidance": [
            "Free electron"
          ],
          "hint": "These are the loosely held electrons that facilitate electrical flow.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        },
        {
          "questionText": "In which shell of an atom are the electrons that are most likely to participate in electrical conduction located?",
          "answerGuidance": [
            "Valence shell",
            "Outer shell"
          ],
          "hint": "It is the shell where the attraction from the nucleus is weakest.",
          "sourceTeachingPointIds": [
            "TP2",
            "TP3"
          ]
        }
      ],
      "deeperQuestionText": "Why are electrons in the valence shell more likely to become 'free' than those in the shells closer to the nucleus?",
      "deeperAnswerGuidance": [
        "They are further from the nucleus",
        "The attraction holding them is weak",
        "The grip of the nucleus is weaker at a distance",
        "They can easily break away"
      ],
      "deeperSourceTeachingPointIds": [
        "TP3",
        "TP4"
      ],
      "hint": "Consider how the distance from the nucleus affects the 'grip' or attraction on the electron."
    },
    {
      "title": "Conductors vs Insulators",
      "basicQuestions": [
        {
          "questionText": "What does a conductor have a large number of that allows electricity to flow?",
          "answerGuidance": [
            "Free electrons"
          ],
          "hint": "These are the loosely bound particles in the valence shell.",
          "sourceTeachingPointIds": [
            "TP1"
          ]
        },
        {
          "questionText": "What is the name for a material where electrons are tightly bound and cannot move easily?",
          "answerGuidance": [
            "Insulator"
          ],
          "hint": "Think of materials like PVC or rubber.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "Which common insulating material is used to contain the flow of electricity in a standard cable?",
          "answerGuidance": [
            "PVC",
            "Polyvinyl chloride"
          ],
          "hint": "It is the plastic-like coating on the outside of the wire.",
          "sourceTeachingPointIds": [
            "TP4"
          ]
        }
      ],
      "deeperQuestionText": "Why is a cable constructed with a copper core surrounded by a PVC sheath rather than being made entirely of one material?",
      "deeperAnswerGuidance": [
        "Copper is a conductor to carry current",
        "PVC is an insulator to contain current",
        "Copper has many free electrons for flow",
        "PVC prevents the flow from escaping the wire",
        "It ensures safety by blocking electron movement to the outside"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP3",
        "TP5"
      ],
      "hint": "Think about the different jobs the inside and the outside of the cable must do."
    },
    {
      "title": "Electron Flow and Current",
      "basicQuestions": [
        {
          "questionText": "What is the term for the directed, continuous flow of free electrons through a conductor?",
          "answerGuidance": [
            "Electric current"
          ],
          "hint": "This is the organized movement of electrons in one direction.",
          "sourceTeachingPointIds": [
            "TP3"
          ]
        },
        {
          "questionText": "What word describes the unified movement of electrons in a single direction when a force is applied?",
          "answerGuidance": [
            "Drift"
          ],
          "hint": "It is the opposite of random movement.",
          "sourceTeachingPointIds": [
            "TP2"
          ]
        },
        {
          "questionText": "What must be provided for electrons to flow effectively through a circuit?",
          "answerGuidance": [
            "Continuous path",
            "Conductive path"
          ],
          "hint": "Electrons cannot flow if there is a break in the material.",
          "sourceTeachingPointIds": [
            "TP5"
          ]
        }
      ],
      "deeperQuestionText": "How does the movement of free electrons in a copper wire change when it is connected to a power source compared to when it is disconnected?",
      "deeperAnswerGuidance": [
        "Changes from random movement to directed flow",
        "Electrons begin to drift in one direction",
        "Movement becomes unified instead of random",
        "An electric current is formed"
      ],
      "deeperSourceTeachingPointIds": [
        "TP1",
        "TP2",
        "TP3"
      ],
      "hint": "Compare 'random movement' with 'directed flow'."
    }
  ]
}

{
  "integrative": {
    "title": "Integrative Close",
    "objective": "Synthesize electron theory with material properties to explain the function of electrical cables.",
    "retrievalTextLines": [
      "Atoms consist of a nucleus and orbiting electrons.",
      "Free electrons are found in the outer valence shell.",
      "Conductors have many free electrons.",
      "Insulators have tightly bound electrons."
    ],
    "questionText": "Using your knowledge of atomic structure, explain why the copper core of a cable allows an electric current to flow while the PVC insulation prevents it from escaping.",
    "answerGuidance": [
      "Copper has many free electrons in its valence shell",
      "These electrons are loosely bound and can move easily between atoms",
      "PVC electrons are tightly bound to their parent atoms",
      "PVC lacks the free electrons required to facilitate a directed flow (current)"
    ],
    "hint": "Focus on the difference in how 'tightly' the atoms in each material hold onto their outer electrons."
  }
}

